368→export const updateJournalService = async(content, title, journalId, userId) => {
369→    if(!journalId){
370→        console.error('journalid is undefined');
371→        throw {status: 400, error: 'journalId is undefined'}
372→    }
373→
374→    if(!userId){
375→        console.error('userId is undefined')
376→        throw({status: 400, error: 'userId is undefined'})
377→    }
378→
379→    const {data: existingJournal, error: existingJournalError} = await supabase
380→    .from('journals')
381→    .select('id, user_id, content, title, post_type')
382→    .eq('id', journalId)
383→    .eq('user_id', userId)
384→    .maybeSingle();
385→
386→    if(existingJournalError){
387→        console.error('failed to fetch existing journal for update', existingJournalError.message);
388→        throw {status: 500, error: 'failed to fetch existing journal for update'};
389→    }
390→
391→    if(!existingJournal){
392→        console.error('journal not found for update');
393→        throw {status: 404, error: 'journal not found for update'};
394→    }
395→
396→    const resolvedTitle = typeof title === 'string' && title.trim() ? title.trim() : existingJournal.title;
397→    if(!resolvedTitle){
398→        console.error('title is undefined');
399→        throw {status: 400, error: 'title is undefined'};
400→    }
401→
402→    let resolvedContent = existingJournal.content;
403→    if(typeof content === 'string' && content.trim()){
404→        resolvedContent = content;
405→    }
406→
407→    if(!resolvedContent){
408→        console.error('text content is missing for text post update');
409→        throw {status: 400, error: 'text content is missing for text post update'};
410→    }
411→
412→    const parseData = parseTextContentSafely(resolvedContent);
413→    if(!parseData){
414→        console.error('failed to parse text content for update');
415→        throw {status: 400, error: 'failed to parse text content for update'};
416→    }
417→
418→    const embeddingBody = parseData.wholeText || '';
419→    const embeddings = await GenerateEmbeddings(resolvedTitle, embeddingBody);
420→
421→    if(!embeddings || !Array.isArray(embeddings) || embeddings.length === 0){
422→        console.error('failed to generate embeddings')
423→        throw {status: 400, error: 'failed to generate embeddings'};
424→    }
425→
426→    const journalData = {
427→        content: resolvedContent,
428→        title: resolvedTitle,
429→        post_type: POST_TYPE_TEXT,
430→        embeddings: embeddings
431→    }
432→
433→    const {data, error} = await supabase
434→    .from('journals')
435→    .update(journalData)
436→    .eq('id', journalId)
437→    .eq('user_id', userId)
438→
439→    if(error){
440→        console.error('supabase error while uploading content:', error.message);
441→        throw{status: 500, error: 'supabase error while uploading content'};
442→    }
443→
444→    // Non-fatal: send mention notifications on edit
445→    try {
446→        const mentionedUserIds = extractMentionUserIds(resolvedContent);
447→        const filtered = mentionedUserIds
448→            .filter(id => id !== userId)
449→            .slice(0, 50);
450→
451→        // Remove old mention notifications for this journal to avoid duplicates
452→        const { error: deleteError } = await supabase
453→            .from('notifications')
454→            .delete()
455→            .eq('type', 'mention')
456→            .eq('journal_id', journalId);
457→
458→        if (deleteError) console.error('[mentions] edit: clear old failed:', deleteError.message);
459→
460→        if (filtered.length > 0) {
461→            const notifRows = filtered.map(receiverId => ({
462→                sender_id: userId,
463→                receiver_id: receiverId,
464→                type: 'mention',
465→                journal_id: journalId,
466→                read: false
467→            }));
468→
469→            const { error: notifError } = await supabase
470→                .from('notifications')
471→                .insert(notifRows);
472→
473→            if (notifError) console.error('[mentions] edit: insert failed:', notifError.message);
474→        }
475→    } catch (mentionErr) {
476→        console.error('[mentions] edit error:', mentionErr?.message || mentionErr);
477→    }
478→
479→    return true;
480→}
