482→export const updateRepostCaptionService = async(journalId, userId, caption) => {
483→    if(!journalId){
484→        throw {status: 400, error: 'journalId is undefined'};
485→    }
486→    if(!userId){
487→        throw {status: 400, error: 'userId is undefined'};
488→    }
489→
490→    const trimmedCaption = typeof caption === 'string' ? caption.trim() : '';
491→    if(trimmedCaption.length > 280){
492→        throw {status: 400, error: 'caption must be 280 characters or less'};
