502→    if(fetchError){
503→        console.error('failed to fetch journal for repost caption update:', fetchError.message);
504→        throw {status: 500, error: 'failed to fetch journal'};
505→    }
506→
507→    if(!journal){
508→        throw {status: 404, error: 'journal not found'};
509→    }
510→
511→    if(!journal.is_repost){
512→        throw {status: 400, error: 'journal is not a repost'};
