 899→    }
 900→
 901→    const normalized = username.trim().toLowerCase();
 902→    const RESERVED_WORDS = ['admin', 'root', 'iskrib', 'iskryb', 'support', 'help', 'api', 'www', 'null', 'undefined'];
 903→    if (RESERVED_WORDS.includes(normalized)) {
