 921→router.post('/update-username', requireAuth, async (req, res) => {
 922→    const userId = req.userId;
 923→    const { username } = req.body;
 924→
 925→    if (!username || typeof username !== 'string') {
 926→        return res.status(400).json({ error: 'username is required' });
 927→    }
 928→
 929→    const trimmed = username.trim();
 930→    if (trimmed.length < 3 || trimmed.length > 50) {
 931→        return res.status(400).json({ error: 'username must be 3-50 characters' });
 932→    }
 933→
 934→    if (!/^[a-zA-Z0-9-]+$/.test(trimmed)) {
 935→        return res.status(400).json({ error: 'username can only contain letters, numbers, and hyphens' });
 936→    }
 937→
 938→    const normalized = trimmed.toLowerCase();
 939→    const RESERVED_WORDS = ['admin', 'root', 'iskrib', 'iskryb', 'support', 'help', 'api', 'www', 'null', 'undefined'];
 940→    if (RESERVED_WORDS.includes(normalized)) {
 941→        return res.status(400).json({ error: 'this username is reserved' });
 942→    }
 943→
 944→    // Check uniqueness
 945→    const { data: existing } = await supabase
 946→        .from('users')
 947→        .select('id')
 948→        .ilike('username', normalized)
 949→        .neq('id', userId)
 950→        .limit(1);
 951→
 952→    if (existing && existing.length > 0) {
 953→        return res.status(409).json({ error: 'username is already taken' });
 954→    }
 955→
 956→    const { error: updateError } = await supabase
 957→        .from('users')
 958→        .update({ username: trimmed.toLowerCase() })
 959→        .eq('id', userId);
 960→
 961→    if (updateError) {
 962→        console.error('update-username error:', updateError.message);
 963→        return res.status(500).json({ error: 'failed to update username' });
 964→    }
 965→
 966→    return res.status(200).json({ message: 'success', username: trimmed.toLowerCase() });
 967→});
