 354→const isSafeRemoteImageUrl = (imageUrl) => {
 355→    try {
 356→        const parsed = new URL(imageUrl);
 357→        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
 358→            return false;
 359→        }
 360→
 361→        const hostname = parsed.hostname.toLowerCase();
 362→        if (!hostname || hostname === 'localhost' || hostname.endsWith('.local') || hostname.endsWith('.internal')) {
 363→            return false;
 364→        }
 365→
 366→        if (net.isIP(hostname) && isPrivateIpAddress(hostname)) {
 367→            return false;
 368→        }
 369→
 370→        return true;
 371→    } catch {
 372→        return false;
 373→    }
 374→};
