 376→const evaluateShareImageCandidate = (rawUrl) => {
 377→    const absoluteUrl = resolveAbsoluteHttpUrl(rawUrl);
 378→    if (!absoluteUrl) {
 379→        return {
 380→            ok: false,
 381→            reason: 'invalid_or_non_http_url',
 382→            resolvedUrl: null,
 383→        };
 384→    }
 385→
 386→    let path = '';
 387→    try {
 388→        const parsed = new URL(absoluteUrl);
 389→        path = String(parsed.pathname || '').toLowerCase();
 390→    } catch {
 391→        return {
 392→            ok: false,
 393→            reason: 'invalid_resolved_url',
 394→            resolvedUrl: null,
 395→        };
 396→    }
 397→
 398→    if (path.endsWith('.svg')) {
 399→        return {
 400→            ok: false,
 401→            reason: 'svg_not_supported_for_share_image',
 402→            resolvedUrl: absoluteUrl,
 403→        };
 404→    }
 405→
 406→    if (!isSafeRemoteImageUrl(absoluteUrl)) {
 407→        return {
 408→            ok: false,
 409→            reason: 'unsafe_remote_url',
 410→            resolvedUrl: absoluteUrl,
 411→        };
 412→    }
 413→
 414→    return {
 415→        ok: true,
 416→        reason: 'ok',
 417→        resolvedUrl: absoluteUrl,
 418→    };
 419→};
