 532→app.use((req, res, next) => {
 533→    metricsState.requests += 1;
 534→    metricsState.inFlight += 1;
 535→
 536→    const startNs = process.hrtime.bigint();
 537→    let byteCount = 0;
 538→
 539→    const originalWrite = res.write.bind(res);
 540→    const originalEnd = res.end.bind(res);
 541→
 542→    res.write = (chunk, encoding, callback) => {
 543→        if (chunk) {
 544→            byteCount += Buffer.isBuffer(chunk)
 545→                ? chunk.length
 546→                : Buffer.byteLength(chunk, typeof encoding === 'string' ? encoding : 'utf8');
 547→        }
 548→        return originalWrite(chunk, encoding, callback);
 549→    };
 550→
 551→    res.end = (chunk, encoding, callback) => {
 552→        if (chunk) {
 553→            byteCount += Buffer.isBuffer(chunk)
 554→                ? chunk.length
 555→                : Buffer.byteLength(chunk, typeof encoding === 'string' ? encoding : 'utf8');
 556→        }
 557→        return originalEnd(chunk, encoding, callback);
 558→    };
 559→
 560→    res.on('finish', () => {
 561→        metricsState.inFlight = Math.max(0, metricsState.inFlight - 1);
 562→        metricsState.responses += 1;
 563→        metricsState.bytesSent += byteCount;
 564→
 565→        const statusBucket = classifyStatusBucket(res.statusCode);
 566→        metricsState.statusBuckets[statusBucket] += 1;
 567→
 568→        const durationMs = Number(process.hrtime.bigint() - startNs) / 1_000_000;
 569→        const routeTemplate = req.route?.path
 570→            ? `${req.baseUrl || ''}${req.route.path}`
 571→            : req.path;
 572→        const routeKey = `${req.method} ${canonicalizeMetricsPath(routeTemplate)}`;
 573→
 574→        let routeStat = metricsState.routeStats.get(routeKey);
 575→        if (!routeStat) {
 576→            if (metricsState.routeStats.size >= METRICS_ROUTE_LIMIT) {
 577→                return;
 578→            }
 579→
 580→            routeStat = {
 581→                count: 0,
 582→                totalDurationMs: 0,
 583→                maxDurationMs: 0,
 584→                bytesSent: 0,
 585→                statusBuckets: { '2xx': 0, '3xx': 0, '4xx': 0, '5xx': 0, other: 0 },
 586→            };
 587→            metricsState.routeStats.set(routeKey, routeStat);
 588→        }
 589→
 590→        routeStat.count += 1;
 591→        routeStat.totalDurationMs += durationMs;
 592→        routeStat.maxDurationMs = Math.max(routeStat.maxDurationMs, durationMs);
 593→        routeStat.bytesSent += byteCount;
 594→        routeStat.statusBuckets[statusBucket] += 1;
 595→    });
 596→
 597→    next();
 598→});
