 49→export const createStoryService = async (userId, title, description, status, privacy, tags, coverFile) => {
 50→    if (!userId) {
 51→        throw { status: 400, error: 'userId is undefined' };
 52→    }
 53→    if (!title || typeof title !== 'string' || title.trim().length === 0) {
 54→        throw { status: 400, error: 'title is required' };
 55→    }
 56→    if (title.length > 200) {
 57→        throw { status: 400, error: 'title must be 200 characters or less' };
 58→    }
 59→    if (description && description.length > 2000) {
 60→        throw { status: 400, error: 'description must be 2000 characters or less' };
 61→    }
 62→
 63→    const validStatuses = ['ongoing', 'completed', 'hiatus'];
 64→    const validPrivacy = ['public', 'private'];
 65→    const storyStatus = validStatuses.includes(status) ? status : 'ongoing';
 66→    const storyPrivacy = validPrivacy.includes(privacy) ? privacy : 'public';
 67→
 68→    let parsedTags = [];
 69→    if (tags) {
 70→        try {
 71→            parsedTags = typeof tags === 'string' ? JSON.parse(tags) : tags;
 72→            if (!Array.isArray(parsedTags)) parsedTags = [];
 73→            parsedTags = parsedTags.slice(0, 10).map(t => String(t).trim()).filter(Boolean);
 74→        } catch {
 75→            parsedTags = [];
 76→        }
 77→    }
 78→
 79→    let coverUrl = null;
 80→    if (coverFile) {
 81→        coverUrl = await imageUploader(coverFile, userId, 'story-covers');
 82→    }
 83→
 84→    const embedding = await GenerateEmbeddings(title.trim(), (description || '').trim());
 85→    if (!embedding || !Array.isArray(embedding) || embedding.length === 0) {
 86→        throw { status: 400, error: 'failed to generate story embedding' };
 87→    }
 88→
 89→    const { data, error } = await supabase
 90→        .from('stories')
 91→        .insert({
 92→            author_id: userId,
 93→            title: title.trim(),
 94→            description: (description || '').trim(),
 95→            cover_url: coverUrl,
 96→            status: storyStatus,
 97→            privacy: storyPrivacy,
 98→            tags: parsedTags,
 99→            embedding,
100→        })
101→        .select(STORY_SELECT_COLUMNS)
102→        .single();
103→
104→    if (error) {
105→        console.error('supabase error creating story:', error.message);
106→        throw { status: 500, error: 'failed to create story' };
107→    }
108→
109→    return stripEmbedding(data);
110→};
