174→export const getStoryByIdService = async (storyId, userId) => {
175→    if (!storyId) {
176→        throw { status: 400, error: 'storyId is required' };
177→    }
178→
179→    const { data: story, error } = await supabase
180→        .from('stories')
181→        .select(STORY_SELECT_COLUMNS)
182→        .eq('id', storyId)
183→        .single();
184→
185→    if (error || !story) {
186→        console.error('supabase error fetching story:', error?.message);
187→        throw { status: 404, error: 'story not found' };
188→    }
189→
190→    // Non-author can't see private stories
191→    if (story.privacy === 'private' && story.author_id !== userId) {
192→        throw { status: 404, error: 'story not found' };
193→    }
194→
195→    // Fetch author profile + chapters in parallel
196→    const [authorMap, chapResult] = await Promise.all([
197→        fetchAuthorProfiles([story.author_id]),
198→        supabase
199→            .from('chapters')
200→            .select('id, chapter_number, title, word_count, status, published_at, created_at')
201→            .eq('story_id', storyId)
202→            .order('chapter_number', { ascending: true }),
203→    ]);
204→
205→    if (chapResult.error) {
206→        console.error('supabase error fetching chapters:', chapResult.error.message);
207→    }
208→
209→    // Filter chapters for non-authors
210→    const isAuthor = story.author_id === userId;
211→    const chapters = chapResult.data || [];
212→    const visibleChapters = isAuthor
213→        ? chapters
214→        : chapters.filter(c => c.status === 'published');
215→
216→    // Fetch user flags
217→    let hasVoted = false;
218→    let inLibrary = false;
219→    let readingProgress = null;
220→
221→    if (userId) {
222→        const [voteRes, libRes, progressRes] = await Promise.all([
223→            supabase.from('story_votes').select('id').eq('story_id', storyId).eq('user_id', userId).maybeSingle(),
224→            supabase.from('story_library').select('id').eq('story_id', storyId).eq('user_id', userId).maybeSingle(),
225→            supabase.from('reading_progress').select('chapter_id, scroll_position, last_read_at').eq('story_id', storyId).eq('user_id', userId).maybeSingle(),
226→        ]);
227→
228→        hasVoted = !!voteRes.data;
229→        inLibrary = !!libRes.data;
230→        readingProgress = progressRes.data || null;
231→    }
232→
233→    return {
234→        ...stripEmbedding(story),
235→        users: authorMap[story.author_id] || null,
236→        chapters: visibleChapters,
237→        has_voted: hasVoted,
238→        in_library: inLibrary,
239→        reading_progress: readingProgress,
240→        is_author: isAuthor,
241→    };
242→};
