 1→/**
 2→ * Walk Lexical JSON content to find the first image src.
 3→ * Returns the src string or null.
 4→ */
 5→const extractPostImage = (contentJson) => {
 6→  try {
 7→    const parsed = typeof contentJson === "string" ? JSON.parse(contentJson) : contentJson;
 8→    if (!parsed?.root) return null;
 9→
10→    const walk = (node) => {
11→      if (!node || typeof node !== "object") return null;
12→
13→      const nodeType = String(node.type || "").toLowerCase();
14→      if (nodeType === "image" || nodeType.includes("image")) {
15→        const src = node.src || node.url || node.image_url || node.imageUrl;
16→        if (typeof src === "string" && src.trim()) return src.trim();
17→      }
18→
19→      if (Array.isArray(node.children)) {
20→        for (const child of node.children) {
21→          const result = walk(child);
22→          if (result) return result;
23→        }
24→      }
25→
26→      return null;
27→    };
28→
29→    return walk(parsed.root);
30→  } catch {
31→    return null;
32→  }
33→};
34→
35→export default extractPostImage;
